                                if      (row === 'LTIR')          sval = parseFloat(((slta * _rateBase) / smh).toFixed(4)).toString();
                                else if (row === 'TRIR')          sval = parseFloat(((srec * _rateBase) / smh).toFixed(4)).toString();
