                        const tIndAmt = projRows.reduce((s,r)=>s+(r.indAmt||0),0);
                        tableBody.push(['TOTAL',tDomM3.toLocaleString(undefined,{maximumFractionDigits:3}),tDomAmt.toLocaleString(undefined,{maximumFractionDigits:2}),tPotLit.toLocaleString(undefined,{maximumFractionDigits:3}),tPotAmt.toLocaleString(undefined,{maximumFractionDigits:2}),tIndM3.toLocaleString(undefined,{maximumFractionDigits:3}),tIndAmt.toLocaleString(undefined,{maximumFractionDigits:2})]);

